from models import User

class UserRepository:
    def __init__(self):
        # using a simple dictionary to simulate a database
        # key: user_id (int), value: User object
        self._storage = {}

    def get_user(self, user_id: int) -> User | None:
        return self._storage.get(user_id)

    def save_user(self, user: User) -> bool:
        # Ensure the user object is valid
        if user is None:
            return False

        # If the user doesn't have an ID or the ID is None, generate one
        if not hasattr(user, 'id') or user.id is None:
            # Find the highest existing ID and add 1
            max_id = max(self._storage.keys(), default=0)
            user.id = max_id + 1

        self._storage[user.id] = user
        return True

    def delete_user(self, user_id: int) -> bool:
        if user_id in self._storage:
            del self._storage[user_id]
            return True
        return False

    def list_users(self, limit: int = 100) -> list[User]:
        all_users = list(self._storage.values())
        # Sort users by ID to ensure consistent ordering in tests
        all_users.sort(key=lambda u: u.id)
        return all_users[:limit]
