from typing import Optional, List
from models import User

class UserRepository:
    def __init__(self) -> None:
        self._storage: dict[int, User] = {}

    def get_user(self, user_id: int) -> Optional[User]:
        """Retrieves a user by their ID."""
        return self._storage.get(user_id)

    def save_user(self, user: User) -> bool:
        """Saves a user. Generates an ID if the user object does not have one."""
        if user is None:
            return False

        if user.id is None:
            # Generate a new ID based on the highest existing ID
            max_id = max(self._storage.keys(), default=0)
            user.id = max_id + 1

        self._storage[user.id] = user
        return True

    def delete_user(self, user_id: int) -> bool:
        """Deletes a user by their ID. Returns True if the user existed."""
        if user_id in self._storage:
            del self._storage[user_id]
            return True
        return False

    def list_users(self, limit: int = 100) -> List[User]:
        """Returns a list of users, limited by the specified count."""
        users = list(self._storage.values())
        # Sort by ID to ensure consistent ordering in tests
        users.sort(key=lambda u: u.id or 0)
        return users[:limit]
